msg.metadataKeys = JSON.stringify(Object.keys(metadata)); // register current metadata keys
/* remove current msg keys */
delete msg.method;
delete msg.params;

return {msg: msg, metadata: metadata, msgType: msgType};

/**
 * Function to calculate the average of an array
 * @param array array to calculate the average
 * @return decimal result of the average
 */
function calculateAverage(array){
    var sum = 0; // declare sum

    for(var i=0;i<array.length;i++)
        sum += array[i].value;

    return sum/array.length;
}

/* get the telemetry keys */
var telemetryKeys = Object.keys(msg);

/* calculate the average, 
delete the telemetry key 
and add an average one */
for(const singleKey of telemetryKeys){
    msg["average_"+singleKey] = calculateAverage(JSON.parse(msg[singleKey]));
    delete msg[singleKey];
}

return {msg: msg, metadata: metadata, msgType: "POST_ATTRIBUTES_REQUEST"};

