configuration.jsScript:
/* get the old keys and the current keys of metadata */
var oldKeys = JSON.parse(msg.metadataKeys);
delete msg.metadataKeys;
var currentKeys = Object.keys(metadata);

/* check if it's a timeseries key
and move it to the msg*/
for(const singleKey of currentKeys){
    if(!oldKeys.includes(singleKey)){ // if the key it's not included it means it's a telemetry one
        msg[singleKey]=metadata[singleKey]; // move to msg part
        delete metadata[singleKey]; // delete the metadata key
    }
}

return {msg: msg, metadata: metadata, msgType: msgType};

var errorList = []; // create the list for errors
const TIMETHRESHOLD = 24; // it maximum hours of difference from the last telemetry of that measure type 

/**
 * Function to establish if the last time of that
 * specific measure was taken before the threshold
 * @param timestamp timestamp of the measure
 * @return TRUE if the difference of time is lower than the threshold, FALSE otherwise
 */
function isLastTelemetryRecent(timestamp){
    return (Date.now() - timestamp) / 1000 / 60 / 60 < TIMETHRESHOLD;
}

/* get the keys and
initialise the variables */
var measures = Object.keys(msg);
var telemetryList;

/* check for each telemetry the
last save of a value */
for(const singleMeasure of measures){
    telemetryList = JSON.parse(msg[singleMeasure]); // get the list of telemetry
    /* check the difference in hours. 
    If the distance exceeds the threshold add an error */
    if(!isLastTelemetryRecent(telemetryList[telemetryList.length-1].ts))
        errorList.push("error_"+singleMeasure);
}

/* if the list has no error found, 
populate the array with a single value */
if(errorList.length === 0)
    errorList.push("values_ok");

return errorList;

